<span class="line"><span class="token punctuation">[</span>Worker-1 <span class="token assign-left variable">depth</span><span class="token operator">=</span><span class="token number">3</span> <span class="token assign-left variable">url</span><span class="token operator">=</span><span class="token string">&#39;http://localhost:8000/bin/python&#39;</span><span class="token punctuation">]</span> <span class="token punctuation">[</span>Worker-2 <span class="token assign-left variable">depth</span><span class="token operator">=</span><span class="token number">3</span> <span class="token assign-left variable">url</span><span class="token operator">=</span><span class="token string">&#39;http://localhost:8000/bin/pip3.10&#39;</span><span class="token punctuation">]</span></span>
